 13→@RequiresApi(Build.VERSION_CODES.O)
 14→class FormFillerAutofillService : AutofillService() {
 15→
 16→    override fun onFillRequest(request: FillRequest, cancel: CancellationSignal, callback: FillCallback) {
 17→        val structure = request.fillContexts.lastOrNull()?.structure ?: return callback.onSuccess(null)
 18→        val db = AppDatabase.get(this)
 19→        val profiles = db.query("SELECT * FROM profiles ORDER BY createdAt DESC", null).use { c ->
 20→            val list = mutableListOf<Pair<Long, String>>()
 21→            while (c.moveToNext()) list.add(c.getLong(0) to c.getString(1))
 22→            list
 23→        }
 24→        if (profiles.isEmpty()) return callback.onSuccess(null)
 25→
 26→        // 收集页面上所有可填充的字段
 27→        val fillableFields = mutableListOf<ParsedField>()
 28→        for (i in 0 until structure.windowNodeCount) {
 29→            parseNode(structure.getWindowNodeAt(i).rootViewNode, fillableFields)
 30→        }
 31→        if (fillableFields.isEmpty()) return callback.onSuccess(null)
 32→
 33→        val response = FillResponse.Builder()
 34→
 35→        for ((profileId, profileName) in profiles) {
 36→            val fields = db.fieldDao().getByProfileSync(profileId)
 37→            if (fields.isEmpty()) continue
 38→
 39→            val dataset = Dataset.Builder()
 40→            var hasMatch = false
 41→
 42→            for (pf in fillableFields) {
 43→                val matched = fields.firstOrNull { matchFieldToHint(it.fieldType, it.label, pf.hints) }
 44→                if (matched != null) {
 45→                    val presentation = RemoteViews(packageName, R.layout.autofill_item).apply {
 46→                        setTextViewText(R.id.tvAutofill, "$profileName: ${matched.label} = ${matched.value}")
 47→                    }
 48→                    dataset.setValue(pf.id, AutofillValue.forText(matched.value), presentation)
 49→                    hasMatch = true
 50→                } else {
 51→                    // 必须为每个字段设置值，否则 dataset 无效；跳过未匹配的
 52→                }
 53→            }
 54→
 55→            if (hasMatch) {
 56→                response.addDataset(dataset.build())
 57→            }
 58→        }
 59→
 60→        try {
 61→            callback.onSuccess(response.build())
 62→        } catch (e: Exception) {
 63→            callback.onSuccess(null)
 64→        }
 65→    }
 66→
 67→    override fun onSaveRequest(request: SaveRequest, callback: SaveCallback) {
 68→        callback.onSuccess()
 69→    }
 70→
 71→    private data class ParsedField(
 72→        val id: android.view.autofill.AutofillId,
 73→        val hints: List<String>
 74→    )
 75→
 76→    private fun parseNode(node: AssistStructure.ViewNode?, fields: MutableList<ParsedField>) {
 77→        node ?: return
 78→        val id = node.autofillId
 79→        if (id != null && node.autofillType == android.view.View.AUTOFILL_TYPE_TEXT) {
 80→            val hints = mutableListOf<String>()
 81→            node.autofillHints?.forEach { hints.add(it.lowercase()) }
 82→            node.hint?.let { hints.add(it.lowercase()) }
 83→            node.text?.toString()?.let { if (it.isNotBlank()) hints.add(it.lowercase()) }
 84→            node.idEntry?.let { hints.add(it.lowercase()) }
 85→            // HTML 属性
 86→            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
 87→                node.htmlInfo?.let { html ->
 88→                    html.attributes?.forEach { p -> hints.add("${p.first}=${p.second}".lowercase()) }
 89→                }
 90→            }
 91→            if (hints.isNotEmpty()) {
 92→                fields.add(ParsedField(id, hints))
 93→            }
 94→        }
 95→        for (i in 0 until node.childCount) {
 96→            parseNode(node.getChildAt(i), fields)
 97→        }
 98→    }
 99→
100→    private fun matchFieldToHint(fieldType: String, label: String, hints: List<String>): Boolean {
101→        val joined = hints.joinToString(" ")
102→        return when (fieldType) {
103→            "name" -> joined.containsAny("姓名", "name", "username", "称")
104→            "id_number" -> joined.containsAny("身份证", "证件", "idcard", "id_number")
105→            "phone" -> joined.containsAny("手机", "电话", "phone", "tel", "mobile")
106→            "address" -> joined.containsAny("地址", "住所", "address", "住址")
107→            "company" -> joined.containsAny("公司", "单位", "company", "企业", "机构")
108→            "postal" -> joined.containsAny("邮编", "postal", "zip")
109→            else -> joined.contains(label.lowercase())
110→        }
111→    }
112→
113→    private fun String.containsAny(vararg keywords: String) = keywords.any { this.contains(it) }
114→}
